def process_saml_response(saml_response):
    try:
        root = ET.fromstring(saml_response)
        assertion = find_assertion(root)
        if assertion is None:
            return None

        attributes = {}
        for attr in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attr.get('Name')
            attr_value = attr.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            attributes[attr_name] = attr_value

        user_data = {
            'username': attributes.get('username')
        }

        return user_data

    except ET.ParseError:
        return None

def find_assertion(root):
    for assertion in root.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion'):
        return assertion
    return None

